/**
 * Web Dashboard — Web Server
 *
 * AUTO-GENERATED by Phoenix VCS
 * Serves the web client HTML, plus health/metrics/modules endpoints.
 */

import { createServer, IncomingMessage, ServerResponse } from 'node:http';

import * as analyticsPanel from './analytics-panel.js';
import * as dashboardPage from './dashboard-page.js';
import * as styles from './styles.js';
import * as taskListDisplay from './task-list-display.js';

// ─── Metrics ─────────────────────────────────────────────────────────────────

const _svcMetrics = {
  requests_total: 0,
  requests_by_path: {} as Record<string, number>,
  errors_total: 0,
  uptime_start: Date.now(),
};

// ─── Module Registry ─────────────────────────────────────────────────────────

const _svcModules = {
  'analytics-panel': analyticsPanel,
  'dashboard-page': dashboardPage,
  'styles': styles,
  'task-list-display': taskListDisplay,
};

// ─── HTML Renderer ───────────────────────────────────────────────────────────

function renderPage(): string {
  // Use DashboardPage to render the complete HTML page
  try {
    const { DashboardPage } = dashboardPage as { DashboardPage: new () => { renderHTML(): string } };
    const page = new DashboardPage();
    return page.renderHTML();
  } catch (err) {
    console.error('Error rendering DashboardPage:', err);
    // Fallback to basic HTML if DashboardPage fails
    return `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="utf-8">
  <meta name="viewport" content="width=device-width, initial-scale=1">
  <title>TaskFlow Dashboard - Error</title>
</head>
<body>
  <h1>Error Loading Dashboard</h1>
  <p>${(err as Error).message}</p>
  <pre>${(err as Error).stack}</pre>
</body>
</html>`;
  }
}

// ─── Router ──────────────────────────────────────────────────────────────────

type Handler = (req: IncomingMessage, res: ServerResponse) => void | Promise<void>;

const routes: Record<string, Handler> = {
  '/': (_req, res) => {
    res.writeHead(200, { 'Content-Type': 'text/html; charset=utf-8' });
    res.end(renderPage());
  },

  '/health': (_req, res) => {
    res.writeHead(200, { 'Content-Type': 'application/json' });
    res.end(JSON.stringify({
      status: 'ok',
      service: 'Web Dashboard',
      uptime: Math.floor((Date.now() - _svcMetrics.uptime_start) / 1000),
      modules: Object.keys(_svcModules),
    }));
  },

  '/metrics': (_req, res) => {
    res.writeHead(200, { 'Content-Type': 'application/json' });
    res.end(JSON.stringify({
      ..._svcMetrics,
      uptime_seconds: Math.floor((Date.now() - _svcMetrics.uptime_start) / 1000),
    }, null, 2));
  },

  '/modules': (_req, res) => {
    const info = Object.entries(_svcModules).map(([name, mod]) => {
      const phoenix = (mod as Record<string, unknown>)._phoenix as Record<string, unknown> | undefined;
      return {
        name,
        risk_tier: phoenix?.risk_tier ?? 'unknown',
        exports: Object.keys(mod).filter(k => k !== '_phoenix'),
      };
    });
    res.writeHead(200, { 'Content-Type': 'application/json' });
    res.end(JSON.stringify(info, null, 2));
  },
};

// ─── Server ──────────────────────────────────────────────────────────────────

function handleRequest(req: IncomingMessage, res: ServerResponse): void {
  const url = req.url ?? '/';
  const path = url.split('?')[0];

  _svcMetrics.requests_total++;
  _svcMetrics.requests_by_path[path] = (_svcMetrics.requests_by_path[path] ?? 0) + 1;

  const handler = routes[path];
  if (handler) {
    try {
      handler(req, res);
    } catch (err) {
      _svcMetrics.errors_total++;
      res.writeHead(500, { 'Content-Type': 'application/json' });
      res.end(JSON.stringify({ error: String(err) }));
    }
  } else {
    res.writeHead(404, { 'Content-Type': 'application/json' });
    res.end(JSON.stringify({
      error: 'Not Found',
      path,
      available: Object.keys(routes),
    }));
  }
}

export function startServer(port?: number): { server: ReturnType<typeof createServer>; port: number; ready: Promise<void> } {
  const requestedPort = port ?? parseInt(process.env.WEB_DASHBOARD_PORT ?? process.env.PORT ?? '3002', 10);
  const server = createServer(handleRequest);
  let actualPort = requestedPort;

  const ready = new Promise<void>(resolve => {
    server.listen(requestedPort, () => {
      const addr = server.address();
      if (addr && typeof addr === 'object') actualPort = addr.port;
      result.port = actualPort;
      console.log(`Web Dashboard listening on http://localhost:${actualPort}`);
      console.log(`  /         — web client`);
      console.log(`  /health   — health check`);
      console.log(`  /metrics  — request metrics`);
      console.log(`  /modules  — registered modules`);
      resolve();
    });
  });

  const result = { server, port: actualPort, ready };
  return result;
}

// Start when run directly
const isMain = process.argv[1]?.endsWith('/web-dashboard/server.js') ||
               process.argv[1]?.endsWith('/web-dashboard/server.ts');
if (isMain) {
  startServer();
}
